import { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import './ActionCenter.css';

const ActionCenter = ({ language, state, caseData }) => {
  const [braveMode, setBraveMode] = useState(false);
  const [identity, setIdentity] = useState({ name: '', contact: '' });
  const [followUpOptIn, setFollowUpOptIn] = useState(false);
  const [complaint, setComplaint] = useState('');
  const [secondOpinion, setSecondOpinion] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  const content = {
    en: {
      title: 'Action Center',
      subtitle: 'Take formal action on your report',
      crisisType: 'Crisis Type',
      severity: 'Severity',
      complaintDraft: 'Generated Complaint Draft',
      braveMode: 'Brave Mode',
      braveModeDesc: 'Include your identity in the complaint (stronger legal standing)',
      nameLabel: 'Your Name',
      contactLabel: 'Contact Information',
      secondOpinion: 'How does this classification feel?',
      correctOption: 'Yes, that is right',
      moreSerious: 'No, it feels more serious',
      notSure: 'I am not sure',
      followUp: 'Follow-Up Check-In',
      followUpDesc: 'We\'ll check in with you in 48 hours to see how you\'re doing',
      downloadButton: 'Download Complaint',
      submitButton: 'Submit to Authorities',
      editButton: 'Edit Complaint',
      saveButton: 'Save Changes',
      backButton: 'Back to Chat',
      legalFramework: 'Legal Framework',
      authorityContact: 'Authority Contact'
    },
    hi: {
      title: 'एक्शन सेंटर',
      subtitle: 'अपनी रिपोर्ट पर औपचारिक कार्रवाई करें',
      crisisType: 'संकट प्रकार',
      severity: 'गंभीरता',
      complaintDraft: 'उत्पन्न शिकायत मसौदा',
      braveMode: 'ब्रेव मोड',
      braveModeDesc: 'शिकायत में अपनी पहचान शामिल करें (मजबूत कानूनी स्थिति)',
      nameLabel: 'आपका नाम',
      contactLabel: 'संपर्क जानकारी',
      secondOpinion: 'यह वर्गीकरण कैसा लगता है?',
      correctOption: 'हां, यह सही है',
      moreSerious: 'नहीं, यह अधिक गंभीर लगता है',
      notSure: 'मुझे यकीन नहीं है',
      followUp: 'फॉलो-अप चेक-इन',
      followUpDesc: 'हम 48 घंटों में आपसे संपर्क करेंगे यह देखने के लिए कि आप कैसे हैं',
      downloadButton: 'शिकायत डाउनलोड करें',
      submitButton: 'अधिकारियों को सबमिट करें',
      editButton: 'शिकायत संपादित करें',
      saveButton: 'परिवर्तन सहेजें',
      backButton: 'चैट पर वापस जाएं',
      legalFramework: 'कानूनी ढांचा',
      authorityContact: 'प्राधिकरण संपर्क'
    }
  };

  const text = content[language] || content.en;

  // State-specific legal frameworks and authorities
  const stateInfo = {
    MH: {
      laws: ['Maharashtra Prohibition of Ragging Act 1999', 'POSH Act 2013', 'UGC Regulations 2009'],
      authority: 'Maharashtra State Women Commission',
      email: 'mswc@maharashtra.gov.in',
      phone: '+91-22-2204-2034'
    },
    DL: {
      laws: ['Delhi Prohibition of Ragging Act 2009', 'POSH Act 2013', 'UGC Regulations 2009'],
      authority: 'Delhi Commission for Women',
      email: 'dcw@delhi.gov.in',
      phone: '+91-11-2338-9090'
    },
    TN: {
      laws: ['Tamil Nadu Prohibition of Ragging Act 1997', 'POSH Act 2013', 'UGC Regulations 2009'],
      authority: 'Tamil Nadu State Women Commission',
      email: 'tnswc@tn.gov.in',
      phone: '+91-44-2432-1234'
    },
    KA: {
      laws: ['Karnataka Educational Institutions Act 1995', 'POSH Act 2013', 'UGC Regulations 2009'],
      authority: 'Karnataka State Women Commission',
      email: 'kswc@karnataka.gov.in',
      phone: '+91-80-2225-4567'
    },
    WB: {
      laws: ['West Bengal Prohibition of Ragging Act 2009', 'POSH Act 2013', 'UGC Regulations 2009'],
      authority: 'West Bengal Commission for Women',
      email: 'wbcw@wb.gov.in',
      phone: '+91-33-2214-5678'
    }
  };

  const currentStateInfo = stateInfo[state] || stateInfo.MH;

  useEffect(() => {
    const data = location.state?.caseData || caseData;
    if (data) {
      generateComplaint(data);
    }
  }, [location.state, caseData, braveMode, identity]);

  const generateComplaint = (data) => {
    const date = new Date().toLocaleDateString('en-IN');
    const complaintText = `
FORMAL COMPLAINT

To: ${currentStateInfo.authority}
Date: ${date}
State: ${state || 'Not specified'}

Subject: Complaint regarding ${data.crisisType || 'harassment'} incident

Incident Description:
Based on the conversation and assessment, this complaint pertains to a ${data.crisisType || 'harassment'} incident with severity level ${data.severity || 'medium'}.

Legal Framework:
${currentStateInfo.laws.map(law => `- ${law}`).join('\n')}

Requested Actions:
1. Immediate investigation of the incident
2. Protection from further harassment/ragging
3. Appropriate disciplinary action against perpetrators
4. Implementation of preventive measures

Session Reference: ${data.sessionId || 'N/A'}

${braveMode && identity.name ? `
Complainant Details:
Name: ${identity.name}
Contact: ${identity.contact}
` : `
Submitted anonymously as per complainant's request.
`}

This complaint is submitted in accordance with the applicable laws and regulations.

Respectfully,
${braveMode && identity.name ? identity.name : 'Anonymous Complainant'}
    `.trim();

    setComplaint(complaintText);
  };

  const handleSecondOpinion = (opinion) => {
    setSecondOpinion(opinion);
    if (opinion === 'more_serious') {
      // Re-evaluate with higher severity
      const updatedData = { 
        ...caseData, 
        severity: Math.min((caseData?.severity || 2) + 1, 4) 
      };
      generateComplaint(updatedData);
    }
  };

  const handleDownload = () => {
    const blob = new Blob([complaint], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `complaint-${Date.now()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSubmit = () => {
    // Create mailto link with pre-filled complaint
    const subject = encodeURIComponent('Formal Complaint - Sahayak AI Platform');
    const body = encodeURIComponent(complaint);
    const mailtoLink = `mailto:${currentStateInfo.email}?subject=${subject}&body=${body}`;
    
    window.open(mailtoLink, '_blank');
    
    // Navigate to follow-up page
    if (followUpOptIn) {
      navigate('/follow-up', { state: { sessionId: caseData?.sessionId } });
    }
  };

  return (
    <div className="action-center">
      <div className="action-container">
        <div className="action-header">
          <button className="back-button" onClick={() => navigate('/chat')}>
            <svg viewBox="0 0 24 24" fill="none">
              <path d="M19 12H5M5 12L12 19M5 12L12 5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>
          <div>
            <h1>{text.title}</h1>
            <p className="subtitle">{text.subtitle}</p>
          </div>
        </div>

        {/* Crisis Summary */}
        <div className="crisis-summary">
          <div className="summary-item">
            <span className="summary-label">{text.crisisType}:</span>
            <span className="summary-value">{caseData?.crisisType || 'Harassment'}</span>
          </div>
          <div className="summary-item">
            <span className="summary-label">{text.severity}:</span>
            <span className={`severity-badge level-${caseData?.severity || 2}`}>
              Level {caseData?.severity || 2}
            </span>
          </div>
        </div>

        {/* Second Opinion */}
        {!secondOpinion && (
          <div className="second-opinion">
            <h3>{text.secondOpinion}</h3>
            <div className="opinion-buttons">
              <button 
                className="opinion-btn correct"
                onClick={() => handleSecondOpinion('correct')}
              >
                ✓ {text.correctOption}
              </button>
              <button 
                className="opinion-btn serious"
                onClick={() => handleSecondOpinion('more_serious')}
              >
                ⚠️ {text.moreSerious}
              </button>
              <button 
                className="opinion-btn unsure"
                onClick={() => handleSecondOpinion('not_sure')}
              >
                ❓ {text.notSure}
              </button>
            </div>
          </div>
        )}

        {/* Legal Framework */}
        <div className="legal-framework">
          <h3>{text.legalFramework}</h3>
          <ul>
            {currentStateInfo.laws.map((law, index) => (
              <li key={index}>{law}</li>
            ))}
          </ul>
        </div>

        {/* Authority Contact */}
        <div className="authority-contact">
          <h3>{text.authorityContact}</h3>
          <div className="contact-info">
            <p><strong>{currentStateInfo.authority}</strong></p>
            <p>📧 {currentStateInfo.email}</p>
            <p>📞 {currentStateInfo.phone}</p>
          </div>
        </div>

        {/* Complaint Draft */}
        <div className="complaint-section">
          <div className="complaint-header">
            <h2>{text.complaintDraft}</h2>
            <button 
              className="edit-button"
              onClick={() => setIsEditing(!isEditing)}
            >
              {isEditing ? text.saveButton : text.editButton}
            </button>
          </div>
          <textarea 
            className="complaint-text"
            value={complaint}
            onChange={(e) => setComplaint(e.target.value)}
            readOnly={!isEditing}
            rows={20}
          />
        </div>

        {/* Brave Mode */}
        <div className="brave-mode-section">
          <div className="brave-mode-toggle">
            <input 
              type="checkbox"
              id="braveMode"
              checked={braveMode}
              onChange={(e) => setBraveMode(e.target.checked)}
            />
            <label htmlFor="braveMode">
              <strong>{text.braveMode}</strong>
              <span className="brave-mode-desc">{text.braveModeDesc}</span>
            </label>
          </div>

          {braveMode && (
            <div className="identity-form">
              <input 
                type="text"
                placeholder={text.nameLabel}
                value={identity.name}
                onChange={(e) => setIdentity({...identity, name: e.target.value})}
                className="identity-input"
              />
              <input 
                type="text"
                placeholder={text.contactLabel}
                value={identity.contact}
                onChange={(e) => setIdentity({...identity, contact: e.target.value})}
                className="identity-input"
              />
            </div>
          )}
        </div>

        {/* Follow-Up */}
        <div className="follow-up-section">
          <div className="follow-up-toggle">
            <input 
              type="checkbox"
              id="followUp"
              checked={followUpOptIn}
              onChange={(e) => setFollowUpOptIn(e.target.checked)}
            />
            <label htmlFor="followUp">
              <strong>{text.followUp}</strong>
              <span className="follow-up-desc">{text.followUpDesc}</span>
            </label>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="action-buttons">
          <button className="download-button" onClick={handleDownload}>
            📥 {text.downloadButton}
          </button>
          <button className="submit-button" onClick={handleSubmit}>
            📤 {text.submitButton}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ActionCenter;
